public static string Camelize(this string input)
{
    var pascalized = input.Pascalize();
    if (pascalized.Length == 0)
    {
        return pascalized;
    }

    return string.Concat(
        char.ToLowerInvariant(pascalized[0]).ToString(),
        pascalized.AsSpan(1));
}

